INSERT INTO yumilk.dbo.brands (name, description, is_active, created_at, deleted_at, modified_at, logo) VALUES (N'Similac', N'Similac là một trong những thương hiệu sữa của Abbott - Tập đoàn chăm sóc sức khỏe hàng đầu thế giới đến từ Hoa Kỳ. Thành lập năm 1888, Abbott chuyên nghiên cứu, phát triển, sản xuất và đưa ra các sản phẩm và dịch vụ chăm sóc sức khỏe. Những sản phẩm của Abbott trải rộng từ dược phẩm, thực phẩm dinh dưỡng đến công nghệ y sinh và thiết bị chuyên dụng phục vụ trong y tế.', 1, N'2024-05-22 00:00:00.6000000', null, N'2024-07-20 15:31:02.1473728', N'https://i.imgur.com/OP5vOM3.png');
INSERT INTO yumilk.dbo.brands (name, description, is_active, created_at, deleted_at, modified_at, logo) VALUES (N'Enfa', N'Enfa là thương hiệu dinh dưỡng nổi tiếng bậc nhất Hoa Kỳ được nhiều ba mẹ ủng hộ và được khuyên dùng bởi các chuyên gia chăm sóc sức khoẻ hàng đầu thế giới. Thương hiệu luôn tiên phong trong công cuộc phát triển những sản phẩm dinh dưỡng chất lượng và an toàn dành cho nhiều đối tượng, bao gồm: trẻ sơ sinh, trẻ nhỏ, mẹ bầu và mẹ đang cho con bú. Enfa gồm các dòng sản phẩm chính như:  Enfamama dành cho mẹ bầu và mẹ cho con bú: bổ sung dinh dưỡng giúp thai kỳ trọn vẹn, đảm bảo sức khoẻ cho cả mẹ và thai nhi.  Các dòng dinh dưỡng bổ sung cho sơ sinh và trẻ nhỏ theo giai đoạn như: Enfa A+1, Enfa A+2, Enfa Grow,...  Các dòng dinh dưỡng đặc biệt cho trẻ như: Enfalac,…', 1, N'2024-05-22 00:00:00.6000000', null, N'2024-07-20 15:32:41.1856368', N'https://i.imgur.com/daIfYcI.jpeg');
INSERT INTO yumilk.dbo.brands (name, description, is_active, created_at, deleted_at, modified_at, logo) VALUES (N'Aptamil', N'Aptamil là sản phẩm dinh dưỡng thuộc tập đoàn Danone (Pháp) - tập đoàn dinh dưỡng trẻ em Số 1 Châu Âu. Thương hiệu được thành lập tại Đức vào năm 1968 và được bán tại Anh năm 1983. Trải qua hơn 40 năm kinh nghiệm trong lĩnh vực, cùng đội ngũ hơn 250 bác sĩ y khoa, chuyên gia dinh dưỡng, nhà khoa học không ngừng nỗ lực trong công cuộc nghiên cứu sữa mẹ và dinh dưỡng đầu đời, Aptamil đã thành công phát triển những công thức độc đáo, đáp ứng nhu cầu dinh dưỡng cho bé yêu ở từng thời kì phát triển.      Những nỗ lực của Aptamil đã đưa thương hiệu trở thành cái tên hàng đầu thế giới trong lĩnh vực dinh dưỡng dành cho trẻ nhỏ. Bên cạnh đó, Aptamil vẫn luôn là nguồn thông tin đáng tin cậy cho bố mẹ và nhiều chuyên gia trong ngành. ', 1, N'2024-05-22 00:00:00.6000000', null, N'2024-07-20 15:33:08.3779574', N'https://i.imgur.com/ItdfgJg.jpeg');
INSERT INTO yumilk.dbo.brands (name, description, is_active, created_at, deleted_at, modified_at, logo) VALUES (N'Nestlé NAN', N'Nhãn hàng sữa bột NAN đến từ Thụy Sĩ mang đến những lựa chọn dinh dưỡng hợp lý theo từng độ tuổi, từng giai đoạn phát triển, giúp trẻ phát triển trọn tiềm năng. Thương hiệu NAN cam kết đồng hành cùng ba mẹ trên hành trình dành trọn những điều tốt nhất cho con. Cam kết đó là kim chỉ nam và cũng chính là DNA của thương hiệu NAN. Với hơn 155 năm kinh nghiệm Nestlé không ngừng tiên phong nghiên cứu & sáng tạo trong lĩnh vực dinh dưỡng dành cho trẻ nhỏ và ứng dụng vào các sản phẩm NAN, để đồng hành cùng ba mẹ nuôi dưỡng trọn tiềm năng trong con.', 1, N'2024-05-22 00:00:00.6000000', null, N'2024-07-20 15:45:25.5097767', N'https://i.imgur.com/sd2WlKh.png');
INSERT INTO yumilk.dbo.brands (name, description, is_active, created_at, deleted_at, modified_at, logo) VALUES (N'Meiji', N'Meiji từ lâu được biết đến là một trong những thương hiệu sản xuất sữa bột cho bé lâu đời bậc nhất tại Nhật Bản và châu Á. Được thành lập năm 1917, sau hơn 100 năm hình thành và phát triển, Meiji đã khẳng định được giá trị thương hiệu số 1 với dây chuyền sản xuất hiện đại, cho ra những sản phẩm chất lượng cao nhất. Tất cả sản phẩm Meiji dù ở các thị trường nước ngoài hay thị trường trong nước đều được sản xuất tại cùng một nhà máy ở tỉnh Saitama, Nhật Bản.     Hướng tới việc tạo ra được loại sữa bột có thành phần gần gũi với trẻ nhỏ, Meiji đã thực hiện dự án “Khoa học sữa mẹ” và cho ra những dòng sữa phù hợp nhất. Tất cả các dòng sữa bột Meiji đều mang lại cho bé thể trạng và sự phát triển toàn diện nhất dựa trên sức mạnh tự nhiên có từ sữa.  ', 1, N'2024-05-22 00:00:00.6000000', null, N'2024-07-20 15:35:24.7012999', N'https://i.imgur.com/5ZMAOmb.png');
INSERT INTO yumilk.dbo.brands (name, description, is_active, created_at, deleted_at, modified_at, logo) VALUES (N'Friso', N'Đôi nét về thương hiệu  Friso Gold là thương hiệu sữa thuộc FrieslandCampina, một trong những tập đoàn sữa liên hợp lớn nhất trên thế giới với doanh thu hàng năm lên đến 10,3 tỷ euro. Tập đoàn sở hữu hơn 14.132 trang trại sữa thành viên ở Hà Lan, Đức và Bỉ, và hơn 140 năm kinh nghiệm trong kinh doanh liên hợp nông trại sữa. Tập đoàn đóng trò quan trọng trong việc cung cấp thực phẩm cho hàng trăm triệu người trên toàn thế giới.  Đồng hành với các nông dân giàu kinh nghiệm trong ngành sữa, các chuyên gia đến thừ thương hiệu Friso không ngừng nghiên cứu và cải tiến, nhằm cung cấp cho mẹ và bé nguồn sữa đạt chất lượng tốt nhất. Friso Gold – với nguồn sữa mát 100% từ Hà Lan, giúp con tự tin lớn khôn trên mọi bước đi trong hành trình khôn lớn.  Một số ưu điểm nổi bật của thương hiệu   . Nguồn sữa mát 100% từ Hà Lan  Với 150 năm kinh nghiệm trong ngành sữa, các chú bò Friso được cung cấp chế độ ăn riêng biệt để đảm bảo tạo ra nguồn sữa chất lượng với các phân tử đạm sữa mềm nhỏ tự nhiên, giúp bé hấp thu nhanh và tiêu hóa dễ dàng', 1, N'2024-05-22 00:00:00.6000000', null, N'2024-07-20 15:35:04.7955536', N'https://i.imgur.com/tkmk85a.png');
INSERT INTO yumilk.dbo.brands (name, description, is_active, created_at, deleted_at, modified_at, logo) VALUES (N'Pediasure', N'Pediasure là một trong những thương hiệu sữa của Abbott - Tập đoàn chăm sóc sức khỏe hàng đầu thế giới đến từ Hoa Kỳ. Thành lập năm 1888, Abbott chuyên nghiên cứu, phát triển, sản xuất và đưa ra các sản phẩm và dịch vụ chăm sóc sức khỏe. Những sản phẩm của Abbott trải rộng từ dược phẩm, thực phẩm dinh dưỡng đến công nghệ y sinh và thiết bị chuyên dụng phục vụ trong y tế.', 1, N'2024-05-22 00:00:00.6000000', null, N'2024-07-20 15:34:44.9186953', N'https://i.imgur.com/Hp73Rbe.png');
