INSERT INTO yumilk.dbo.brands (name, description, is_active, created_at, deleted_at, modified_at, logo) VALUES (N'YokoGold', N'YOKOGOLD  là 1 trong những thương hiệu sữa thuộc Vinamilk - Tập đoàn dinh dưỡng hàng đầu Việt Nam, thương hiệu Quốc gia và thuộc Top 50 Công ty sữa lớn nhất thế giới. Trải qua gần 40 năm miệt mài nghiên cứu và tích cực đổi mới, cái tên Vinamilk đã nhận được sự tin yêu của người dân Việt Nam và cả người nước ngoài. Tuy nhiên, không vì thành tích đó mà Vinamilk dừng bước, thương hiệu vẫn không ngừng nỗ lực khẳng định mình qua tinh thần cầu tiến, sáng tạo trong cả công nghệ sản xuất và tính đa dạng qua từng dòng sản phẩm. Các sản phẩm của Vinamilk luôn đạt chất lượng hàng đầu theo tiêu chuẩn quốc tế và đáp ứng được nhu cầu của nhiều đối tượng khách hàng.', 1, N'2024-06-17 00:00:00.0000000', null, N'2024-07-20 15:31:36.0062653', N'https://i.imgur.com/Z1ezeD8.png');
INSERT INTO yumilk.dbo.brands (name, description, is_active, created_at, deleted_at, modified_at, logo) VALUES (N'PureLac', null, 0, N'2024-06-17 00:00:00.0000000', null, null, N'https://i.imgur.com/mKRLb5I.jpeg');
INSERT INTO yumilk.dbo.brands (name, description, is_active, created_at, deleted_at, modified_at, logo) VALUES (N'Humana', N'Humana là một trong 2 tập đoàn đứng hàng đầu tại Đức, nằm trong TOP 10 các Công ty lớn nhất của châu Âu. Thành lập vào 1950, với hơn 70 năm kinh nghiệm trong công cuộc nghiên cứu, sản xuất sữa và các sản phẩm chế biến từ sữa cho bé yêu, Humana đã thành công xuất khẩu các dòng sản phẩm đa dạng, chất lượng cao đến với gần 70 quốc gia trên toàn thế giới.  100% sản phẩm của Humana được sản xuất dưới quy trình khép kín, được kiểm soát hoàn toàn theo quy trình nghiêm ngặt: sữa bò chất lượng cao thu được từ các nông trại xanh & sạch, được bảo quản lạnh và vận chuyển nhanh tới các nhà máy. Tại đây, Humana tiếp tục áp dụng quy trình công nghệ hiện đại trong khâu sản xuất, chế biến và đóng gói, đảm bảo cho ra thị trường những dòng sản phẩm đạt chất lượng cao để cung ứng cho người tiêu dùng toàn cầu .', 1, N'2024-06-17 00:00:00.0000000', null, N'2024-07-20 15:36:00.1106217', N'https://i.imgur.com/bnucNnu.png');
